  "inlineSchema": "// ============================================================\n// Prisma Schema for School Management Platform (SMP)\n// Database: MySQL 9.7\n// ============================================================\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ─── Enums ──────────────────────────────────────────────────\n\n/// User roles within the platform\nenum Role {\n  ADMIN\n  TEACHER\n  PARENT\n}\n\n/// Possible attendance statuses for a student on a given day\nenum AttendanceStatus {\n  PRESENT\n  ABSENT\n}\n\n// ─── Models ─────────────────────────────────────────────────\n\n/// Central authentication entity.\n/// auth_identifier stores the login credential:\n///   - email for ADMIN\n///   - emp_id for TEACHER\n///   - mobile number for PARENT\nmodel User {\n  id              Int      @id @default(autoincrement())\n  role            Role\n  auth_identifier String   @unique\n  password_hash   String? // nullable — parents authenticate via OTP\n  createdAt       DateTime @default(now()) @map(\"created_at\")\n  updatedAt       DateTime @updatedAt @map(\"updated_at\")\n\n  // Relations\n  teacher  Teacher? // A TEACHER user has exactly one Teacher profile\n  students Student[] // A PARENT user owns zero-or-more students\n\n  @@map(\"users\")\n}\n\n/// Student record, linked to a parent User via parentMobile.\nmodel Student {\n  id           Int    @id @default(autoincrement())\n  name         String\n  className    String @map(\"class_name\")\n  parentMobile String @map(\"parent_mobile\")\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  // Relations\n  parent     User         @relation(fields: [parentMobile], references: [auth_identifier])\n  attendance Attendance[]\n  marks      Mark[]\n\n  @@map(\"students\")\n}\n\n/// Teacher profile, 1-to-1 with a User of role TEACHER.\nmodel Teacher {\n  id                 Int     @id @default(autoincrement())\n  userId             Int     @unique @map(\"user_id\")\n  name               String\n  empId              String  @unique @map(\"emp_id\")\n  phone              String? @unique @map(\"phone_number\")\n  mustChangePassword Boolean @default(true) @map(\"must_change_password\")\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  // Relations\n  user        User                @relation(fields: [userId], references: [id])\n  assignments TeacherAssignment[]\n  marks       Mark[]\n\n  @@map(\"teachers\")\n}\n\n/// Academic subject (e.g. Mathematics, Science).\nmodel Subject {\n  id   Int    @id @default(autoincrement())\n  name String @unique\n\n  // Relations\n  assignments TeacherAssignment[]\n  marks       Mark[]\n\n  @@map(\"subjects\")\n}\n\n/// A school class/section (e.g. \"10-A\", \"9-B\").\n/// Managed independently so admins can pre-create classes\n/// before students are enrolled.\nmodel Class {\n  id        Int      @id @default(autoincrement())\n  name      String   @unique\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@map(\"classes\")\n}\n\n/// Maps a teacher to a class + subject combination.\n/// A teacher can teach multiple subjects across multiple classes.\nmodel TeacherAssignment {\n  id        Int    @id @default(autoincrement())\n  teacherId Int    @map(\"teacher_id\")\n  className String @map(\"class_name\")\n  subjectId Int    @map(\"subject_id\")\n\n  // Relations\n  teacher Teacher @relation(fields: [teacherId], references: [id])\n  subject Subject @relation(fields: [subjectId], references: [id])\n\n  // A teacher cannot be assigned the same subject in the same class twice\n  @@unique([teacherId, className, subjectId])\n  @@map(\"teacher_assignments\")\n}\n\n/// Daily attendance record for a student.\nmodel Attendance {\n  id        Int              @id @default(autoincrement())\n  studentId Int              @map(\"student_id\")\n  date      DateTime\n  status    AttendanceStatus\n\n  // Relations\n  student Student @relation(fields: [studentId], references: [id])\n\n  // One attendance entry per student per day\n  @@unique([studentId, date])\n  @@map(\"attendance\")\n}\n\n/// Exam marks for a student in a specific subject, graded by a teacher.\nmodel Mark {\n  id        Int    @id @default(autoincrement())\n  studentId Int    @map(\"student_id\")\n  subjectId Int    @map(\"subject_id\")\n  teacherId Int    @map(\"teacher_id\")\n  score     Float\n  maxScore  Float  @default(100) @map(\"max_score\")\n  examName  String @map(\"exam_name\")\n\n  // Relations\n  student Student @relation(fields: [studentId], references: [id])\n  subject Subject @relation(fields: [subjectId], references: [id])\n  teacher Teacher @relation(fields: [teacherId], references: [id])\n\n  // A student can only have one mark per subject per exam\n  @@unique([studentId, subjectId, examName])\n  @@map(\"marks\")\n}\n\n// ─── Announcement Models ──────────────────────────────────────\n\nenum Audience {\n  TEACHER\n  PARENT\n  BOTH\n}\n\nmodel Announcement {\n  id        Int      @id @default(autoincrement())\n  title     String\n  content   String   @db.Text\n  target    Audience\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@map(\"announcements\")\n}\n",
